-- Listar todas as companies
SELECT id, name FROM companies;

-- Contar usuários por company
SELECT companyId, COUNT(*) as total_usuarios FROM users GROUP BY companyId;

-- Contar vendas por company
SELECT companyId, COUNT(*) as total_vendas FROM sales GROUP BY companyId;

-- Contar vendas históricas por company
SELECT companyId, COUNT(*) as total_historicas FROM historicalSales GROUP BY companyId;

-- Contar comissões por company
SELECT companyId, COUNT(*) as total_comissoes FROM commissions GROUP BY companyId;

